// NewSRPCSpacewaveSessionResourceServiceHandler creates a new handler for the given implementation.
inline std::unique_ptr<SRPCSpacewaveSessionResourceServiceHandler> NewSRPCSpacewaveSessionResourceServiceHandler(SRPCSpacewaveSessionResourceServiceServer* impl) {
  return std::make_unique<SRPCSpacewaveSessionResourceServiceHandler>(impl);
}

// SRPCRegisterSpacewaveSessionResourceService registers the server implementation with the mux.
// The returned handler must outlive the mux registration.
inline std::pair<std::unique_ptr<SRPCSpacewaveSessionResourceServiceHandler>, starpc::Error> SRPCRegisterSpacewaveSessionResourceService(starpc::Mux* mux, SRPCSpacewaveSessionResourceServiceServer* impl) {
  auto handler = NewSRPCSpacewaveSessionResourceServiceHandler(impl);
  starpc::Error err = mux->Register(handler.get());
  if (err != starpc::Error::OK) {
    return {nullptr, err};
  }
  return {std::move(handler), starpc::Error::OK};
}

